import {
  createEditor,
  ParagraphNode,
  TextNode,
  LineBreakNode,
} from "lexical";
import { HeadingNode } from "@lexical/rich-text";
import { oraTheme } from "./theme.js";

const nodes = [ParagraphNode, HeadingNode, TextNode, LineBreakNode];

/**
 * Create a fresh Lexical editor pre-configured for Ora blocks.
 *
 * @param {HTMLElement} rootElement
 * @param {boolean} [editable=true]
 * @returns {import("lexical").LexicalEditor}
 */
export function createBlockEditor(rootElement, editable = true) {
  const editor = createEditor({
    namespace: "ora",
    nodes,
    theme: oraTheme,
    onError: (e) => console.error("Lexical error:", e),
    editable,
  });

  editor.setRootElement(rootElement);
  rootElement.setAttribute("contenteditable", String(editable));
  rootElement.setAttribute("role", "textbox");
  rootElement.setAttribute("aria-multiline", "true");
  return editor;
}

export { ParagraphNode, HeadingNode, TextNode, LineBreakNode };

